// ============================================================
// HydraNet - Utilities API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

// GET /api/utilities - List all utilities
export async function GET() {
  try {
    const utilities = await prisma.utility.findMany({
      include: {
        manager: {
          select: { id: true, name: true, email: true },
        },
        _count: {
          select: { dmas: true, reports: true },
        },
      },
      orderBy: { name: 'asc' },
    })

    const formattedUtilities = utilities.map((utility) => ({
      ...utility,
      managerId: utility.manager?.id || null,
      managerName: utility.manager?.name || 'Unassigned',
      dmasCount: utility._count.dmas,
      reportsCount: utility._count.reports,
    }))

    return NextResponse.json(formattedUtilities)
  } catch (error) {
    console.error('Error fetching utilities:', error)
    return NextResponse.json(
      { error: 'Failed to fetch utilities' },
      { status: 500 }
    )
  }
}

// POST /api/utilities - Create a new utility
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    const utility = await prisma.utility.create({
      data: {
        name: data.name,
        description: data.description,
        status: data.status || 'active',
      },
      include: {
        manager: {
          select: { id: true, name: true, email: true },
        },
      },
    })

    return NextResponse.json(utility, { status: 201 })
  } catch (error) {
    console.error('Error creating utility:', error)
    return NextResponse.json(
      { error: 'Failed to create utility' },
      { status: 500 }
    )
  }
}

// PUT /api/utilities - Update a utility
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    if (!data.id) {
      return NextResponse.json(
        { error: 'Utility ID is required' },
        { status: 400 }
      )
    }

    const utility = await prisma.utility.update({
      where: { id: data.id },
      data: {
        name: data.name,
        description: data.description,
        status: data.status,
      },
      include: {
        manager: {
          select: { id: true, name: true, email: true },
        },
        _count: {
          select: { dmas: true, reports: true },
        },
      },
    })

    const formattedUtility = {
      ...utility,
      managerName: utility.manager?.name || 'Unassigned',
      dmasCount: utility._count.dmas,
      reportsCount: utility._count.reports,
    }

    return NextResponse.json(formattedUtility)
  } catch (error) {
    console.error('Error updating utility:', error)
    return NextResponse.json(
      { error: 'Failed to update utility' },
      { status: 500 }
    )
  }
}

// DELETE /api/utilities - Delete a utility
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')

    if (!id) {
      return NextResponse.json(
        { error: 'Utility ID is required' },
        { status: 400 }
      )
    }

    await prisma.utility.delete({
      where: { id },
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Error deleting utility:', error)
    return NextResponse.json(
      { error: 'Failed to delete utility' },
      { status: 500 }
    )
  }
}
